import{extensionDescriptionProp as e,extensionNameProp as t,isCollapsedProp as n}from"../../data/properties.js";import r from"../../../node_modules/.pnpm/uuid@14.0.0/node_modules/uuid/dist/v4.js";import{EXTENSION_TYPE as i}from"../../data/blockTypes.js";import{CHAR_COUNTER_TYPE as a}from"../character-counter/blockType.js";import{PLACE_TYPE as o}from"../geo/blockTypes.js";import{SRS_SM25_TYPE as s}from"../srs-rescheduling/schema.js";import{TODO_TYPE as c}from"../todo/schema.js";import{exampleExtensions as l}from"../../extensions/exampleExtensions.js";var u=`Tutorial`,d=`Tutorial (vim)`,f=`extensions`,p={fold:"press `z` (or `Shift+Z` to collapse the current block into its parent and jump up to it)",edit:"press `i` (or `a` to enter at end of line, or double-click the block)",exitEdit:"press `Esc`",newBelow:"press `o` (or `Shift+O` to create above)",enterCreates:"— or, while editing any block, press `Enter` to split / create a new one",move:"`j` / `k` (or arrow keys)",panelHop:"`h` to the panel on the left, `l` to the right (or arrow keys)",firstLast:"`gg` jumps to the top of the panel, `Shift+G` to the last block in it",jumpMany:"`Ctrl+d` / `Ctrl+u` jump down / up by ~8 bullets",startSelect:"press `Space` (or `v`) to select the focused bullet; `Shift+J` / `Shift+K` then grow the selection down / up — the first press selects the current block, each next press adds the neighbour",delete:"press `d d` or `Delete`; to remove several at once, select them first (see the **Multi-select** section) and press `Delete`",properties:"press `t`",copyRef:"focus the block and press `y r` (yank reference); `y e` yanks an embed, `y y` the whole subtree, `y c` just this block's text, `y l` a shareable link",paste:"`p` pastes after the focused block, `Shift+P` before",undo:"`u` (or `Cmd+Z` anywhere)",redo:"`Ctrl+R` (or `Cmd+Shift+Z` anywhere)"},m={fold:"while editing, `Cmd+Up` (`Ctrl+Up`) collapses the block and `Cmd+Down` (`Ctrl+Down`) expands it — or click the `▸` / `▾` chevron next to my bullet on hover (on touch it stays visible, and the block's swipe menu has a **Collapse** item)",edit:`click anywhere in my text to start typing`,exitEdit:``,newBelow:"press `Enter` at the end of a bullet to create a new one below (`Shift+Enter` inserts a line break inside)",enterCreates:``,move:"while editing, `↑` / `↓` — at the top/bottom line they hop to the block above / below",panelHop:`click into the panel you want (keyboard panel-hop needs vim mode)`,firstLast:``,jumpMany:``,startSelect:"while editing, `Shift+↓` / `Shift+↑` at a block edge first select the current block, then extend the selection down / up with each further press",delete:"select it (or several — see the **Multi-select** section) and press `Delete`; for a single empty block, `Backspace` at its start removes it and merges into the block above",properties:'open the command palette with `Cmd+K` and run "Toggle block properties"',copyRef:'open the on-block quick-actions menu ("Copy Ref" / "Copy Embed"); keyboard yanks (`y r` / `y e`) need vim mode',paste:"`Cmd+V` — pastes after the focused block",undo:"`Cmd+Z`",redo:"`Cmd+Shift+Z`"},h={zoomIn:"`Cmd+.` (`Ctrl+.` on Linux/Windows)",zoomOut:"`Cmd+,` (`Ctrl+,` on Linux/Windows)",openInPanel:"`Cmd+Shift+.` (`Ctrl+Shift+.`)",closePanel:"`Ctrl+W`",commandPalette:"`Cmd+K` (`Ctrl+K`)",quickFind:"`Cmd+P` (`Ctrl+P`)",findReplace:"`Cmd+Shift+F` (`Ctrl+Shift+F`)",back:"`Cmd+[` / `Cmd+]` (`Ctrl+[` / `Ctrl+]`)",today:"`Ctrl+Shift+`` ` (every platform)",prevNextDay:"`Ctrl+Shift+[` / `Ctrl+Shift+]`",appendToday:"`Ctrl+Shift+N`"},g=e=>{let t=e===`vim`?p:m,n=t=>e===`default`?` ${t}`:``,i=e===`vim`?"**This is the vim-keybindings tutorial.** To follow it, vim mode needs to be on — if it isn't, run **Manage extensions** from the command palette (`Cmd+K`) and tick **Vim normal mode**. Prefer the default keys? See [[Tutorial]].":"**This is the default tutorial.** Vim keybindings are off by default. Want them? Run **Manage extensions** from the command palette (`Cmd+K`), tick **Vim normal mode**, then read [[Tutorial (vim)]].",l=r();return[{content:i,...e===`default`?{children:[{content:'New to "vim keybindings"? **It lets you move and restructure your outline straight from the keyboard.** With it on, a block gains a *normal mode*: single-click (or `Esc`) *focuses* a block instead of editing it, and from there the keys do the work — `j`/`k` between blocks, `h`/`l` between panels, `z` folds, `d d` deletes, `y r` copies a reference, `i` starts editing. If you live on the keyboard it\'s worth a try; flip it on as above and the shortcuts in [[Tutorial (vim)]] take over.'}]}:{}},_(`Welcome`,[`This is a malleable thought medium. Every line below is a **block** you can link, drag around, fold, and extend — including this tutorial itself.`,`Bullets are blocks. Bullets nest. Everything else builds on that.`,`Don't just read — try the keys/clicks on each bullet as you go. Edit anything; this tutorial is just blocks in your workspace.`,`The first few sections cover the essentials; the deeper ones below start **folded** to keep this scannable — expand any that interest you (that fold/unfold is itself a core gesture you'll use everywhere).`]),_(`Try the basics`,[`These bullets are here for fiddling with — read each one, try the key/click, then edit the bullet to make this tutorial yours.`,"Press `Tab` to indent me under the bullet above (`Shift+Tab` to outdent). Try it now.",`New block: ${t.newBelow}${t.enterCreates?` `+t.enterCreates:``}.`,{content:`Fold a block's children: ${t.fold} with that block focused. Try folding the bullet below.`,children:[{content:`I'll vanish when my parent is folded. Fold the parent again to bring me back.`},{content:`A folded parent shows a halo around its bullet so you can spot it from a distance.`}]},`Edit a block: ${t.edit}.${t.exitEdit?` Exit editing: ${t.exitEdit}.`:``}`,`Delete a block: ${t.delete}.`]),_(`Move around`,[`Between blocks: ${t.move}.${n("Vim mode lets you move between blocks with `j` / `k` without entering the editor.")}`,...t.firstLast?[t.firstLast]:[],...t.jumpMany?[t.jumpMany]:[],`Zoom into a block (treat it as the new root of the view): ${h.zoomIn}. Zoom back out: ${h.zoomOut}.`,`Back / forward through your navigation history: ${h.back}.`]),_(`Side panels`,[`Panels sit side by side. Each panel has its own focused block, its own zoom level, and its own edit state — opening something in a new panel means you keep what you were looking at.`,`Open the focused block in a new side panel: ${h.openInPanel}. Close the current panel: ${h.closePanel}.`,`Move between panels: ${t.panelHop}.`,"Wiki-link / block-ref clicks pick a destination based on modifiers. Try them on this link → [[extensions]]: plain click replaces the current panel, `Shift+Alt+Click` opens it in a brand new side panel, `Shift+Click` puts it in a vertical sidebar stack, `Alt+Click` opens it in the main panel. (Plain `Cmd+Click` / `Ctrl+Click` falls through to a browser new-tab as usual.)",`In quick-find (${h.quickFind}): \`Shift+Enter\` (or \`Cmd+Enter\` / \`Ctrl+Enter\`) opens the selected page in a new panel instead of replacing the current view.`,`Quick capture into a side panel: ${h.appendToday} appends a new block to today's daily note in a side panel without taking you away from where you are.`]),v(`Multi-select`,[`${y(t.startSelect)}.`,"Then `Tab`, fold, `Delete`, copy, paste, move — every block-level action applies to the whole selection.","Press `Esc` to clear the selection."]),_(`Pages & links`,[`Wiki links — text wrapped in double square brackets becomes a clickable link to (or creates) a page with that name. Try the link on the next bullet: [[extensions]] takes you to the extensions page (one of the other seeded pages in this workspace).`,`Find or create any page: ${h.quickFind}. Type to filter; pressing Enter on a missing name creates it.`,`Command palette: ${h.commandPalette}. **Every** action in the app is searchable here with its key shown — use this when you forget a shortcut, or to find actions that have no default binding.`,`Find and replace across the workspace: ${h.findReplace}.`,{content:"Block refs and embeds — wiki links point at a *page* (resolved by name). A block ref `((block-id))` points at one specific block anywhere in your workspace; an embed `!((block-id))` renders the target block inline instead of as a link.",children:[{id:l,content:`👋 I am the demo target. Copy a ref or embed to me (${e===`vim`?"focus me and press `y r` / `y e`":`open my quick-actions menu → "Copy Ref" / "Copy Embed"`}), then paste in a new bullet to see the result.`,children:[{content:`I'm a child of the demo target. Embeds bring children along — so the bare-embed bullet further down will render me too.`}]},{content:`Demo ref → ((${l})) — clicking this link navigates to the demo target above.`},{content:"The bullet below this one is a bare embed (`!((<id>))` on its own line, nothing else). It renders the demo target inline — and notice the child of the demo target comes along too:"},{content:`!((${l}))`}]}]),_(`Backlinks`,[`Links are two-way. Open a page (or zoom into any block) and a **Backlinks** section appears below its content, listing every block elsewhere that links here — so a page accretes context from everywhere it's mentioned without you maintaining it.`,`Each referencing block shows a small **reference-count badge**; click it to expand those backlinks inline, right where you are, without navigating away. Click again to collapse.`,`The Backlinks section has a Flat / Grouped switcher in its header. Flat is one plain list; Grouped clusters the references by a shared key — e.g. the page each one lives on, or a type/attribute they share — so related mentions (say, every daily note that links here) sit together.`,`See it live: open [[extensions]] and scroll to its **Backlinks** — this tutorial links there from several bullets, so they all show up listed under that page.`]),v(`Search`,[`QuickFind (${h.quickFind}) searches page aliases first, then block content. Press Enter to open the selected result; if the name is missing, QuickFind can create a new page for it.`,"When you search for several words, all of them must appear, in any order: `project notes` matches blocks that contain both `project` and `notes`.",'Wrap text in quotes for an exact phrase: `"project notes"` only matches that contiguous text.',"Use uppercase `OR` for alternatives: `project OR meeting` finds either term.",'Use a leading minus to exclude a term when the query also has something positive to search for: `project -archived` and `-archived project` both mean "project, but not archived". By itself, `-archived` searches for the literal text `-archived`.',"Punctuation stays literal when it is part of what you typed: `2024-01`, `sync -`, and `foo/bar` search for those characters instead of acting like special syntax.",`For a dedicated workspace-wide text sweep, open Find and replace: ${h.findReplace}.`]),v(`Properties & types`,[`Properties are typed key/value pairs attached to any block. To open the properties panel on a focused block: ${t.properties}.${n("With vim mode on, this is just `t`.")}`,"Try giving me a property — e.g. `priority: high`. It will appear under my content.","Types attach behavior to a block via the special `types` property. `types = ['page']` makes a block a page — addressable by name (through its aliases) and resolvable from wiki links, wherever it lives in the tree. `types = ['extension']` makes it an extension — see below.",`Aliases (a list property on a page) let you reach the page from multiple names — including ones with spaces or different casing. Wiki links resolve through aliases.`,`Every property you define is catalogued on the [[Properties]] page, and every type on the [[Types]] page — open either to see what exists in this workspace.`]),_(`Typed blocks — behaviour from a tag`,["Beyond identity, a type can attach *behaviour* to a block. Add the type via the `types` property (see above) or a block's quick-actions menu. A few that ship by default:",{content:"**Todo** — type `todo` adds a checkbox to the block; click it to toggle done (done items strike through). Great for inline task lists anywhere in your outline.",children:[{content:`Buy milk — tick the checkbox to mark me done.`,type:c}]},{content:"**Video** — paste a video URL (YouTube, Vimeo, and more) as a block's content and it renders an inline player — no type needed. Switch the player to its **notes view** (the notes icon on the player) to jot notes beside the video; `1:23`-style timestamps you type there become clickable seeks. The block below is a live demo — open its notes view and try the timestamps in the note beside it:",children:[{content:`https://www.youtube.com/watch?v=aqz-KE-bpKQ`,children:[{content:`Notes sit beside the player. Click 0:10 to jump there, or 1:00 for later — each timestamp is a seek link.`}]}]},{content:"**Character counter** — type `char-counter` shows a live character count under the block, with an optional per-block limit. The limit is visual only — it never blocks typing.",children:[{content:`Draft a tweet here — edit me and watch the count below track length against the 280 limit (it warns past it, never blocks).`,type:a,typeProperties:{"char:limit":280}}]},{content:`**Spaced repetition** — turn any block into a flashcard and let the app schedule reviews for you (SM-2.5 algorithm).`,children:[{content:`Grade a focused block to make it a card and set its next review: open its quick-actions menu and pick a grade`+(e===`vim`?", or press `Ctrl+Shift+1`–`4` (Again / Hard / Good / Easy)":``)+`.`},{content:"Run **Open SRS review** from the command palette (or `Ctrl+Shift+R`) to open a deck of every card due today or earlier. In the deck, reveal the answer (`Space` / `Enter`) then grade it `1`–`4` (or click) — the card reschedules and the deck moves on."},{content:`Demo card — What's the capital of France? Grade me (or open SRS review) to schedule my first review; the answer is the child below.`,type:s,children:[{content:`Paris`}]}]}]),_(`Places & maps`,["Real-world locations are first-class. Every place — a Google POI, a friend's neighborhood, a coordinate pin on a hike — becomes a typed **Place** block carrying `place:lat`, `place:lng`, `place:address`, and `place:googlePlaceId`.","Type `@` at the start of a block or after whitespace to open the **place picker**. It searches your existing Places first, then offers Google Places matches; picking either inserts `[[Place Name]]` as a wikilink and creates the Place page if it didn't exist yet.",'`@` with no query (or `@here`) surfaces a **Use current location** option — pulls nearby POIs from browser geolocation, plus "Drop pin here" and "Create named location…" fallbacks for ad-hoc spots.',`Give any block a **location property**: open properties (${t.properties}) and add a \`location\` field — its value is a ref to a Place page. Many notes can share one Place (the coords live in exactly one block, so editing the Place updates every reference).`,`The [[Locations]] page at the workspace root holds every Place. Open it to see a **map of every Place** in your workspace; click a marker for an info card with name/address and a jump-to link.`,{content:"Make any block its own map: add `map` to its `types`. The block then renders an inline map above its children showing every Place reachable in its subtree — both descendants with a `location` prop AND descendants that body-wikilink to a `[[Place]]`. A trip page tagged `map` becomes a map of the trip; a project page tagged `map` becomes a map of the project. Live demo (a `map`-tagged block over two Places):",type:`map`,children:[{content:`Eiffel Tower`,type:o,typeProperties:{"place:lat":48.8584,"place:lng":2.2945}},{content:`Louvre Museum`,type:o,typeProperties:{"place:lat":48.8606,"place:lng":2.3376}}]},`Each Place page itself renders with a mini-map of just that one pin, so a Place behaves like a "location card" with the coordinates always visible.`]),v(`Daily notes`,[`Open today's daily note: ${h.today}. This is also the default landing page on a fresh open.`,`Step through daily notes: ${h.prevNextDay} (previous / next).`,`Every daily note is filed under the [[Journal]] page — open it for a reverse-chronological list of them all.`,...e===`vim`?["Scrub a date in place: focus a dated block and **hold `s`**. While held, `k` / `↑` move the date +1 day and `j` / `↓` −1 day; `l` / `→` +7 days and `h` / `←` −7 days. Release `s` to commit, `Esc` to cancel."]:["**Scrub a date in place** — nudge a dated block's date forward or back without retyping it. This one's a vim-mode perk: tick **Vim normal mode** in **Manage extensions**, then focus the date and **hold `s`**, moving by day (`j` / `k`) or week (`h` / `l`). On a phone, a two-finger horizontal drag does it with no vim needed."]]),v(`Undo, redo, copy, paste`,[`Undo: ${t.undo}. Redo: ${t.redo}.`,`Copy a block ref / embed: ${t.copyRef}. (See "Pages & links" above for what those are.)`,`Paste blocks: ${t.paste}.`]),v(`Settings — preferences, shortcuts, themes & extensions`,[`Open preferences: run **Open preferences** from the command palette (${h.commandPalette}) — it has no default shortcut.`,`Remap any shortcut: run **Customize keyboard shortcuts** from the command palette. It lists every action grouped by context — click a binding and press the new keys to rebind it, or reset / disable it; conflicts are flagged, and your overrides sync to your other devices.`,"Change the look: each theme has its own command — run **Theme: <name>** from the command palette to apply it directly (e.g. `Theme: Solarized Dark`). Eight ship built-in — light and dark variants of Sunset Warm, Indigo, and Solarized, plus a plain Light and Dark — and extensions can register their own.","Run **Manage extensions** from the command palette to open the extensions tree — every extension can be toggled on or off there, and the toggle syncs to your other devices. Vim mode itself is an extension (`system:vim-normal-mode`); it's off by default. Tick it to get vim normal-mode keys (and switch this tutorial to the vim variant); untick it for the default click-to-edit experience."]),v(`On mobile`,[`On a phone-sized screen the app swaps in touch affordances:`,`A **bottom navigation bar** gives one-tap access to the sidebar, a new block, append-to-today, today's daily note, search, the command palette, and undo.`,"While editing, a **keyboard toolbar** floats above the on-screen keyboard with indent / outdent, move up / down, `[[` page-reference and `((` block-reference inserts, undo / redo, and a Done button to dismiss the keyboard.","**Swipe a block** to reveal its quick-actions menu — Copy, Copy Ref / Embed, Open in panel, Properties, Collapse, Zoom in, Delete. This is how you reach the per-block actions on touch — the same ones vim binds to keys (`z`, `t`, `y r`, …) — without a keyboard.",`Swipe a block to the right to cycle its todo / done state.`,`Scrub a date: drag a **dated** block sideways with **two fingers** — right moves the date forward, left back, with an overlay previewing the new date as you drag. Two fingers so it never clashes with one-finger scroll or the swipe menu. For a bigger jump, the swipe menu has a **Reschedule** sheet.`]),v(`Workspaces & encryption`,[`A workspace is an independent collection of blocks — many top-level pages and daily notes, not a single tree. Create or switch workspaces from the workspace switcher; you start as the owner and can invite others from workspace **Settings**.`,`New workspaces can be **end-to-end encrypted** — tick "End-to-end encrypted" when creating one. Block content and properties are then encrypted on your device before syncing; the server only ever stores ciphertext.`,`You hold the only key. On creation the app shows the **workspace key once** and makes you save it (a password manager is ideal) and retype its last characters to confirm. There is **no recovery** — lose the key and the data becomes permanently unreadable. On a new device, paste the key to unlock.`,`To collaborate on an encrypted workspace, invite the person via Settings, then send them the key yourself over a channel you trust — the app never transmits it.`]),v(`Extensions`,["**Everything** in this app — the renderer, the vim plugin, daily notes — is an extension. You can author your own; the host loads them out of `types = ['extension']` blocks.",`See [[extensions]] for explanatory bullets, a set of working example extensions, and a renderer demo to enable and play with.`]),v(`Agent runtime — drive this workspace from your terminal`,["The app exposes a runtime bridge for coding agents and scripts. The browser tab runs a local relay; a CLI in your terminal submits commands that execute **inside the live app runtime** — same `Repo`, same workspace, same PowerSync SQLite, same resolved facets.","Get the CLI: install the published package with `npm i -g @knowledge-medium/agent-cli` — that puts a `kmagent` command on your PATH. (Prefer not to install? Prefix any command with `npx @knowledge-medium/agent-cli` instead of `kmagent`.)",`Pairing (one-time per browser profile + app origin):`,{content:"`kmagent connect` — prints an app URL, opens the token dialog when you load it, then waits for you to paste the token back into the terminal. The secret persists in `~/.config/knowledge-medium/agent-bridge.json`."},`Common operations once paired:`,{content:`Status & health`,children:[{content:"`kmagent ping` — health-check the bridge."},{content:"`kmagent status` — detailed `/health` info (uses the persisted secret)."}]},{content:`Querying the workspace`,children:[{content:'`kmagent sql all "SELECT id, content FROM blocks LIMIT 5"` — runs against the local SQLite mirror.'},{content:"`kmagent eval 'return repo.activeWorkspaceId'` — runs arbitrary JS in the app runtime; the return value is serialized back."}]},{content:`Mutating the workspace`,children:[{content:`\`kmagent create-block '{"parentId":"<id>","content":"Created by agent"}'\` — typed helper for the common case.`},{content:"`kmagent eval 'await createBlock({parentId: ..., content: ...})'` — same operation via the eval surface; useful for batching or conditional logic."}]},"Runtime bindings available inside `eval`: `repo`, `db`, `runtime`, `safeMode`, `sql`, `block`, `getBlock`, `getSubtree`, `createBlock`, `updateBlock`, `moveBlock`, `deleteBlock`, `restoreBlock`, `installExtension`, `setExtensionEnabled`, `uninstallExtension`, `actions`, `renderers`, `refreshAppRuntime`, `React`, `ReactDOM`, `window`, `document`. Use these to script edits, drive extensions, dump subtrees, or wire an agent into your workflow.","Defaults & security: the bridge binds to `http://127.0.0.1:8787` (loopback only); only configured app origins can talk to it. Override the pairing target with `AGENT_RUNTIME_APP_URL`, browser endpoint with `VITE_AGENT_RUNTIME_URL`, CLI endpoint with `AGENT_RUNTIME_URL`. Allow extra origins via `AGENT_RUNTIME_ALLOWED_ORIGINS` (comma-separated, no paths).","See the **Agent Runtime Access** section of `README.md` for full setup, plus `kmagent pair-url` if you want a bridge-only pairing URL."])]},_=(e,t,r={})=>({content:e,...r.collapsed?{properties:{[n.name]:!0}}:{},children:t.map(e=>typeof e==`string`?{content:e}:e)}),v=(e,t)=>_(e,t,{collapsed:!0}),y=e=>e.length===0?e:e[0].toUpperCase()+e.slice(1),b=()=>[{content:`**Anything** in this app is an extension — the default block renderer, the vim plugin, daily notes, find-and-replace. The host loads core ones at startup; the rest are blocks like the ones below.`},{content:"An extension block is a block with `types = ['extension']`. Its content is a TS/JSX module whose `default` export is an `AppExtension` — a `FacetContribution`, an array of them, or a function returning one. Imports resolve through the page-global importmap, so importing a symbol from its real module (e.g. `@/extensions/core.js`) returns the same module instance the running app uses."},{content:"Author one: create a block, give it `types = ['extension']`, paste the source, then open **Extensions settings** from the command palette and tick the row to enable it."},{content:`User extensions start **disabled**. The Extensions settings tree lets you toggle each row; the override is per-device and persists across reloads.`},{content:`After editing an extension's source, run **Reload extensions** from the command palette to pick up your changes.`},{content:`Re-insert these examples under any focused block via the **Insert example extensions** command in the palette.`},...l.map(e=>x(e.id))],x=n=>{let r=l.find(e=>e.id===n);if(!r)throw Error(`exampleSection: unknown example "${n}"`);let a={content:r.source,type:i,typeProperties:{[t.name]:r.name,[e.name]:r.description}},o=[{content:`**How to use:** ${S[n]}`},a],s=C[n];return s&&o.push(s),{content:r.name,children:o}},S={"hello-renderer":"Enable in Extensions settings, then add the property `user:hello = true` to any block — its content area will render with the custom hello variant.","fold-all-action":"Enable, then (with vim mode on, so the focused block is in normal mode) press `Cmd+Shift+U` (`Ctrl+Shift+U`) — every visible descendant of the current view's root folds or unfolds together.","emoji-react":"Enable, then Alt+click any block (or, with vim mode on, focus a block and press `Cmd+Shift+E` / `Ctrl+Shift+E`) — cycles a 🔥 / 👍 / 🎉 / ❤️ reaction below the block's content.","kudos-facet":"Enable, then set a block's `renderer` property to `kudos-banner` — the block renders with the Kudos banner appended. Other extensions can contribute to the `user.kudos` facet to extend it.","split-layout":"Enable, then add the property `user:layout = split` to any block — its content and children will render side by side instead of stacked.","layout-renderer-override":`Enable to wrap **every** panel with a custom debug-style frame. Disable the row in Extensions settings to revert. (No per-block property — applies workspace-wide.)`,"default-renderer-placeholder":`Enable to swap the fallback block renderer so empty blocks show a muted "empty block" placeholder in read mode. Disable to revert. (Applies workspace-wide.)`},C={"hello-renderer":{content:"Try it: enable `hello-renderer` above, then this block renders with the custom variant (it carries `user:hello = true`).",properties:{"user:hello":!0}},"fold-all-action":void 0,"emoji-react":void 0,"kudos-facet":void 0,"split-layout":{content:"Try it: enable `split-layout` above, then this block renders content and children side by side (it carries `user:layout = split`). The bullet below me will appear to my right.",properties:{"user:layout":`split`},children:[{content:`I sit beside the content in split mode.`}]},"layout-renderer-override":void 0,"default-renderer-placeholder":void 0};export{f as EXTENSIONS_PAGE_TITLE,u as TUTORIAL_DEFAULT_TITLE,d as TUTORIAL_VIM_TITLE,b as extensionsPageOutline,g as tutorialOutline};
//# sourceMappingURL=outline.js.map